const reviews = $input.item.json.reviews || [];
const firm = $('Her Firma İçin').item.json;
const accessToken = $('Access Token Yenile').item.json.access_token;

// Yalnızca yanıtsız yorumları filtrele
const unanswered = reviews.filter(r => !r.reviewReply);

return unanswered.map(r => ({
  json: {
    firm_id: firm.id,
    firm_name: firm.name,
    firm_sector: firm.sector,
    system_prompt: firm.system_prompt || '',
    approval_mode: firm.approval_mode,
    response_length: firm.response_length || 'medium',
    info_card: firm.info_card || {},
    gmb_location_id: firm.gmb_location_id,
    access_token: accessToken,
    gmb_review_id: r.reviewId,
    reviewer_name: r.reviewer?.displayName || 'Anonim',
    reviewer_id: r.reviewer?.isAnonymous ? null : (r.reviewer?.displayName || null),
    rating: ({'ONE':1,'TWO':2,'THREE':3,'FOUR':4,'FIVE':5})[r.starRating] || 3,
    review_text: r.comment || '',
    review_date: r.createTime,
  }
}));

const raw = $input.item.json.message?.content || '{}';
let analysis;
try {
  // Markdown kod bloğu varsa temizle
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { sentiment: 'neutral', topics: [], importance_score: 3, keywords: [], has_critical_keyword: false, critical_keywords: [] };
}

const review = $('Yeni Yorum mu?').item.json;

return [{ json: { ...review, analysis } }];

const review = $('Analizi Parse Et').item.json;
const template = $input.item.json;
const ic = review.info_card || {};

const lengthMap = { short: '1-2 cümle', medium: '3-4 cümle', long: 'detaylı 5+ cümle' };
const length = lengthMap[review.response_length] || '3-4 cümle';

const systemPrompt = [
  `Sen ${review.firm_name} adına cevap veren bir müşteri hizmetleri asistanısın.`,
  review.system_prompt || '',
  ic.address    ? `Adres: ${ic.address}` : '',
  ic.hours      ? `Çalışma saatleri: ${ic.hours}` : '',
  ic.highlights ? `Öne çıkan ürünler/hizmetler: ${ic.highlights}` : '',
  ic.faq        ? `Sık sorulan sorular: ${ic.faq}` : '',
  ic.forbidden_info ? `Kesinlikle söyleme: ${ic.forbidden_info}` : '',
].filter(Boolean).join('\n');

const userPrompt = [
  `${review.rating} yıldızlı müşteri yorumu:`,
  `"${review.review_text || '(yorum metni yok)'}"`,
  '',
  template.opening ? `Şablon Açılış: ${template.opening}` : '',
  template.body    ? `Şablon Gövde Yönlendirme: ${template.body}` : '',
  template.closing ? `Şablon Kapanış: ${template.closing}` : '',
  '',
  `${length} uzunluğunda profesyonel bir cevap yaz. Yalnızca cevap metnini döndür.`,
].filter(s => s !== null).join('\n');

return [{ json: { ...review, template_id: template.id || null, systemPrompt, userPrompt } }];

const review = $('Prompt Oluştur').item.json;
const aiResult = $input.item.json;

const aiResponse = aiResult.message?.content || '';
const tokensInput = aiResult.usage?.prompt_tokens || 0;
const tokensOutput = aiResult.usage?.completion_tokens || 0;
const costUsd = (tokensInput * 0.0000025) + (tokensOutput * 0.00001);

// 1-2 yıldız her zaman onay bekler
const forcePending = review.rating <= 2;
const autoPublish = !review.approval_mode && !forcePending;

return [{ json: {
  ...review,
  ai_response: aiResponse,
  tokens_input: tokensInput,
  tokens_output: tokensOutput,
  cost_usd: costUsd,
  auto_publish: autoPublish,
  new_status: autoPublish ? 'auto_published' : 'pending',
} }];
